import re

def eval_expr(s: str) -> float:
    if not s or not s.strip():
        raise ValueError("Empty expression")

    # Tokenize: order matters — ** and // before * and /
    token_pattern = re.compile(
        r'\d+\.?\d*'    # integers / decimals: 3, 3.14, 3.
        r'|\.\d+'       # decimals starting with dot: .14
        r'|\*\*'        # power operator
        r'|//'          # floor division
        r'|[+\-*/%()]'  # single-char operators and parens
    )

    tokens = token_pattern.findall(s)

    # Detect invalid / unexpected characters
    reconstructed = ''.join(tokens)
    cleaned = re.sub(r'\s', '', s)
    if reconstructed != cleaned:
        raise ValueError(f"Invalid characters in expression: {s!r}")

    pos = [0]

    def peek():
        return tokens[pos[0]] if pos[0] < len(tokens) else None

    def consume(expected=None):
        tok = peek()
        if tok is None:
            raise ValueError("Unexpected end of expression")
        if expected is not None and tok != expected:
            raise ValueError(f"Expected '{expected}', got '{tok}'")
        pos[0] += 1
        return tok

    # Grammar (lowest → highest precedence):
    #   expr           → additive
    #   additive       → multiplicative (('+' | '-') multiplicative)*
    #   multiplicative → unary (('*' | '/' | '//' | '%') unary)*
    #   unary          → '-' unary | power
    #   power          → primary ('**' unary)*   [right-assoc]
    #   primary        → NUMBER | '(' expr ')'

    def parse_expr():
        return parse_additive()

    def parse_additive():
        left = parse_multiplicative()
        while peek() in ('+', '-'):
            op = consume()
            right = parse_multiplicative()
            left = left + right if op == '+' else left - right
        return left

    def parse_multiplicative():
        left = parse_unary()
        while peek() in ('*', '/', '//', '%'):
            op = consume()
            right = parse_unary()
            if op == '*':
                left = left * right
            elif op == '/':
                if right == 0:
                    raise ValueError("Division by zero")
                left = left / right
            elif op == '//':
                if right == 0:
                    raise ValueError("Floor division by zero")
                left = left // right
            elif op == '%':
                if right == 0:
                    raise ValueError("Modulo by zero")
                left = left % right
        return left

    def parse_unary():
        if peek() == '-':
            consume()
            return -parse_unary()
        return parse_power()

    def parse_power():
        base = parse_primary()
        if peek() == '**':
            consume()
            exp = parse_unary()   # right-associative: recurse into unary
            return base ** exp
        return base

    def parse_primary():
        tok = peek()
        if tok is None:
            raise ValueError("Unexpected end of expression")
        if tok == '(':
            consume('(')
            val = parse_expr()
            if peek() != ')':
                raise ValueError(f"Expected ')', got {peek()!r}")
            consume(')')
            return val
        # Must be a number
        try:
            val = float(tok)
            consume()
            return val
        except (ValueError, TypeError):
            raise ValueError(f"Unexpected token: {tok!r}")

    result = parse_expr()

    if pos[0] != len(tokens):
        raise ValueError(f"Unexpected token {tokens[pos[0]]!r} after valid expression")

    return result

