import re

def eval_expr(s: str) -> float:
    if not s or not s.strip():
        raise ValueError("Empty expression")

    # Tokenize: order matters — ** before *, // before /
    token_re = re.compile(r'\d+\.?\d*|\.\d+|\*\*|//|[+\-*/%()]|\s+')
    tokens = []
    pos = 0
    while pos < len(s):
        m = token_re.match(s, pos)
        if not m:
            raise ValueError(f"Invalid character '{s[pos]}' at position {pos}")
        tok = m.group(0)
        if not tok.isspace():
            tokens.append(tok)
        pos = m.end()

    if not tokens:
        raise ValueError("Empty expression")

    idx = [0]

    def peek():
        return tokens[idx[0]] if idx[0] < len(tokens) else None

    def consume():
        tok = tokens[idx[0]]
        idx[0] += 1
        return tok

    # Grammar (lowest to highest precedence):
    # expr   : term   (('+' | '-') term)*
    # term   : unary  (('*' | '//' | '/' | '%') unary)*
    # unary  : '-' unary | power
    # power  : primary ('**' unary)?        [right-assoc; unary on RHS allows 2**-3]
    # primary: NUMBER | '(' expr ')'

    def parse_expr():
        left = parse_term()
        while peek() in ('+', '-'):
            op = consume()
            right = parse_term()
            left = left + right if op == '+' else left - right
        return left

    def parse_term():
        left = parse_unary()
        while peek() in ('*', '//', '/', '%'):
            op = consume()
            right = parse_unary()
            try:
                if op == '*':
                    left = left * right
                elif op == '//':
                    left = left // right
                elif op == '/':
                    left = left / right
                else:  # %
                    left = left % right
            except ZeroDivisionError:
                raise ValueError("Division or modulo by zero")
        return left

    def parse_unary():
        if peek() == '-':
            consume()
            return -parse_unary()
        return parse_power()

    def parse_power():
        base = parse_primary()
        if peek() == '**':
            consume()
            exp = parse_unary()  # right-assoc, unary allowed on RHS
            try:
                return base ** exp
            except ZeroDivisionError:
                raise ValueError("Zero raised to a negative power")
        return base

    def parse_primary():
        tok = peek()
        if tok is None:
            raise ValueError("Unexpected end of expression")
        if tok == '(':
            consume()
            val = parse_expr()
            if peek() != ')':
                raise ValueError("Mismatched parentheses: expected ')'")
            consume()
            return val
        # Must be a number
        if tok in ('+', '-', '*', '/', '//', '%', '**', ')'):
            raise ValueError(f"Unexpected operator '{tok}'")
        try:
            num = float(tok)
            consume()
            return num
        except ValueError:
            raise ValueError(f"Invalid token '{tok}'")

    result = parse_expr()

    if idx[0] < len(tokens):
        raise ValueError(f"Unexpected token '{tokens[idx[0]]}' at position {idx[0]}")

    return result
